//! skymesh-wifi-pluto — homespun WiFi endpoint for a local Skymesh Pluto bridge.
//!
//! The daemon does two deliberately separate jobs:
//! - broadcasts a small JSON service advertisement over WiFi multicast so Skymesh
//!   peers can discover this host without a registry;
//! - exposes a guarded HTTP control surface that can preflight or drive PlutoSDR
//!   transmit through the existing libiio command-line tools.
//!
//! AP mode is explicit. The daemon can generate a hostapd config for SSID
//! `skymesh`, and on Linux it can optionally spawn hostapd. macOS hotspot/AP
//! creation is an OS-controlled feature, so this binary refuses actual AP
//! execution there instead of confusing service multicast with a visible BSSID.
//!
//! Real RF transmit is fail-closed: POST /pluto/transmit only executes when the
//! process was started with --enable-tx and the ephemeral libiio build exists.

use serde::{Deserialize, Serialize};
use serde_json::json;
use std::io::Read;
use std::net::UdpSocket;
use std::path::{Path, PathBuf};
use std::process::{Child, Command, Stdio};
use std::sync::Arc;
use std::thread;
use std::time::{Duration, SystemTime, UNIX_EPOCH};
use tiny_http::{Header, Method, Request, Response, Server, StatusCode};

const DEFAULT_HTTP_BIND: &str = "0.0.0.0:8732";
const DEFAULT_PUBLIC_HOST: &str = "127.0.0.1";
const DEFAULT_ADVERTISE_GROUP: &str = "239.69.0.69";
const DEFAULT_ADVERTISE_PORT: u16 = 8732;
const DEFAULT_INTERVAL_MS: u64 = 2_000;
const DEFAULT_LIBIIO_BUILD: &str = "/tmp/libiio_build/build";
const DEFAULT_PLUTO_URI: &str = "usb:0.5.5";
const DEFAULT_IIO_ATTR: &str = "/tmp/libiio_build/build/tests/iio_attr";
const DEFAULT_IIO_WRITEDEV: &str = "/tmp/libiio_build/build/tests/iio_writedev";
const DEFAULT_TX_LO_HZ: u64 = 433_920_000;
const DEFAULT_SAMPLE_RATE_HZ: u64 = 2_400_000;
const DEFAULT_GAIN_DB: i32 = -40;
const DEFAULT_RF_BANDWIDTH_HZ: u64 = 2_400_000;
const DEFAULT_BUFFER_SIZE: usize = 4096;
const DEFAULT_AP_SSID: &str = "skymesh";
const DEFAULT_AP_CHANNEL: u8 = 6;
const DEFAULT_HOSTAPD_BIN: &str = "hostapd";

#[derive(Clone, Debug)]
struct Config {
    http_bind: String,
    public_host: String,
    advertise_group: String,
    advertise_port: u16,
    advertise_interval: Duration,
    node_id: String,
    service_id: String,
    enable_tx: bool,
    pluto_uri: String,
    libiio_build: PathBuf,
    iio_attr: PathBuf,
    iio_writedev: PathBuf,
    default_tx_lo_hz: u64,
    default_sample_rate_hz: u64,
    default_gain_db: i32,
    default_rf_bandwidth_hz: u64,
    default_buffer_size: usize,
    ap_mode: bool,
    ap_interface: Option<String>,
    ap_ssid: String,
    ap_channel: u8,
    ap_passphrase: Option<String>,
    ap_config_out: Option<PathBuf>,
    ap_config_only: bool,
    ap_run_hostapd: bool,
    hostapd_bin: String,
}

#[derive(Debug, Deserialize)]
struct TxRequest {
    iq_path: String,
    tx_lo_hz: Option<u64>,
    sample_rate_hz: Option<u64>,
    hardwaregain_db: Option<i32>,
    rf_bandwidth_hz: Option<u64>,
    buffer_size: Option<usize>,
    cyclic: Option<bool>,
    preflight_only: Option<bool>,
}

#[derive(Debug, Serialize)]
struct Advertisement {
    schema_version: &'static str,
    service: &'static str,
    node_id: String,
    service_id: String,
    http_url: String,
    pluto_uri: String,
    tx_enabled: bool,
    endpoints: Vec<&'static str>,
    unix_ms: u64,
}

#[derive(Debug, Serialize)]
struct PlutoPreflight {
    ok: bool,
    tx_enabled: bool,
    pluto_uri: String,
    libiio_build: String,
    framework: String,
    iio_attr: String,
    iio_writedev: String,
    reason: Option<String>,
}

fn now_ms() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0)
}

fn usage() -> ! {
    eprintln!(
        "usage: skymesh-wifi-pluto [--http-bind ADDR:PORT] [--public-host HOST] \
         [--advertise-group ADDR] [--advertise-port PORT] [--advertise-interval-ms N] \
         [--node-id ID] [--service-id ID] [--enable-tx] [--pluto-uri URI] \
         [--libiio-build PATH] [--iio-attr PATH] [--iio-writedev PATH] \
         [--ap-mode --ap-interface IFACE --ap-config-out PATH|--ap-run-hostapd \
          [--ap-ssid skymesh] [--ap-channel N] [--ap-passphrase WPA2PASS] \
          [--ap-config-only] [--hostapd-bin hostapd]]"
    );
    std::process::exit(2);
}

fn parse_config() -> Config {
    let mut cfg = Config {
        http_bind: DEFAULT_HTTP_BIND.to_string(),
        public_host: DEFAULT_PUBLIC_HOST.to_string(),
        advertise_group: DEFAULT_ADVERTISE_GROUP.to_string(),
        advertise_port: DEFAULT_ADVERTISE_PORT,
        advertise_interval: Duration::from_millis(DEFAULT_INTERVAL_MS),
        node_id: "skymesh-pluto-local".to_string(),
        service_id: "gnosis.skymesh.wifi-pluto.v1".to_string(),
        enable_tx: false,
        pluto_uri: DEFAULT_PLUTO_URI.to_string(),
        libiio_build: PathBuf::from(DEFAULT_LIBIIO_BUILD),
        iio_attr: PathBuf::from(DEFAULT_IIO_ATTR),
        iio_writedev: PathBuf::from(DEFAULT_IIO_WRITEDEV),
        default_tx_lo_hz: DEFAULT_TX_LO_HZ,
        default_sample_rate_hz: DEFAULT_SAMPLE_RATE_HZ,
        default_gain_db: DEFAULT_GAIN_DB,
        default_rf_bandwidth_hz: DEFAULT_RF_BANDWIDTH_HZ,
        default_buffer_size: DEFAULT_BUFFER_SIZE,
        ap_mode: false,
        ap_interface: None,
        ap_ssid: DEFAULT_AP_SSID.to_string(),
        ap_channel: DEFAULT_AP_CHANNEL,
        ap_passphrase: None,
        ap_config_out: None,
        ap_config_only: false,
        ap_run_hostapd: false,
        hostapd_bin: DEFAULT_HOSTAPD_BIN.to_string(),
    };

    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--http-bind" => cfg.http_bind = args.next().unwrap_or_else(|| usage()),
            "--public-host" => cfg.public_host = args.next().unwrap_or_else(|| usage()),
            "--advertise-group" => cfg.advertise_group = args.next().unwrap_or_else(|| usage()),
            "--advertise-port" => {
                cfg.advertise_port = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--advertise-interval-ms" => {
                let ms = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage());
                cfg.advertise_interval = Duration::from_millis(ms);
            }
            "--node-id" => cfg.node_id = args.next().unwrap_or_else(|| usage()),
            "--service-id" => cfg.service_id = args.next().unwrap_or_else(|| usage()),
            "--enable-tx" => cfg.enable_tx = true,
            "--pluto-uri" => cfg.pluto_uri = args.next().unwrap_or_else(|| usage()),
            "--libiio-build" => {
                cfg.libiio_build = PathBuf::from(args.next().unwrap_or_else(|| usage()))
            }
            "--iio-attr" => cfg.iio_attr = PathBuf::from(args.next().unwrap_or_else(|| usage())),
            "--iio-writedev" => {
                cfg.iio_writedev = PathBuf::from(args.next().unwrap_or_else(|| usage()))
            }
            "--tx-lo-hz" => {
                cfg.default_tx_lo_hz = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--sample-rate-hz" => {
                cfg.default_sample_rate_hz = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--hardwaregain-db" => {
                cfg.default_gain_db = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--rf-bandwidth-hz" => {
                cfg.default_rf_bandwidth_hz = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--buffer-size" => {
                cfg.default_buffer_size = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--ap-mode" => cfg.ap_mode = true,
            "--ap-interface" => cfg.ap_interface = Some(args.next().unwrap_or_else(|| usage())),
            "--ap-ssid" => cfg.ap_ssid = args.next().unwrap_or_else(|| usage()),
            "--ap-channel" => {
                cfg.ap_channel = args
                    .next()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or_else(|| usage())
            }
            "--ap-passphrase" => cfg.ap_passphrase = Some(args.next().unwrap_or_else(|| usage())),
            "--ap-config-out" => {
                cfg.ap_config_out = Some(PathBuf::from(args.next().unwrap_or_else(|| usage())))
            }
            "--ap-config-only" => cfg.ap_config_only = true,
            "--ap-run-hostapd" => cfg.ap_run_hostapd = true,
            "--hostapd-bin" => cfg.hostapd_bin = args.next().unwrap_or_else(|| usage()),
            "--help" | "-h" => usage(),
            other => {
                eprintln!("skymesh-wifi-pluto: unknown arg {other}");
                usage();
            }
        }
    }
    cfg
}

fn validate_ap_config(cfg: &Config) -> Result<(), String> {
    if !cfg.ap_mode {
        return Ok(());
    }
    if cfg.ap_interface.as_deref().unwrap_or("").is_empty() {
        return Err("--ap-mode requires --ap-interface IFACE".to_string());
    }
    if cfg.ap_ssid.is_empty() || cfg.ap_ssid.len() > 32 {
        return Err("--ap-ssid must be 1..32 bytes for hostapd".to_string());
    }
    if !(1..=165).contains(&cfg.ap_channel) {
        return Err("--ap-channel must be in 1..165".to_string());
    }
    if let Some(passphrase) = cfg.ap_passphrase.as_deref() {
        if passphrase.len() < 8 || passphrase.len() > 63 {
            return Err("--ap-passphrase must be 8..63 characters for WPA2-PSK".to_string());
        }
    }
    if cfg.ap_config_out.is_none() && !cfg.ap_run_hostapd {
        return Err("--ap-mode requires --ap-config-out PATH or --ap-run-hostapd".to_string());
    }
    Ok(())
}

fn hostapd_config(cfg: &Config) -> Result<String, String> {
    validate_ap_config(cfg)?;
    let iface = cfg
        .ap_interface
        .as_deref()
        .ok_or_else(|| "--ap-interface missing".to_string())?;
    let mut lines = vec![
        format!("interface={iface}"),
        "driver=nl80211".to_string(),
        format!("ssid={}", cfg.ap_ssid),
        "hw_mode=g".to_string(),
        format!("channel={}", cfg.ap_channel),
        "ieee80211n=1".to_string(),
        "wmm_enabled=1".to_string(),
        "auth_algs=1".to_string(),
        "ignore_broadcast_ssid=0".to_string(),
    ];
    if let Some(passphrase) = cfg.ap_passphrase.as_deref() {
        lines.extend([
            "wpa=2".to_string(),
            "wpa_key_mgmt=WPA-PSK".to_string(),
            "rsn_pairwise=CCMP".to_string(),
            format!("wpa_passphrase={passphrase}"),
        ]);
    }
    Ok(format!("{}\n", lines.join("\n")))
}

fn prepare_ap_mode(cfg: &Config) -> Result<Option<Child>, String> {
    if !cfg.ap_mode {
        return Ok(None);
    }
    let rendered = hostapd_config(cfg)?;
    let config_path = match cfg.ap_config_out.as_deref() {
        Some(path) => {
            std::fs::write(path, rendered.as_bytes())
                .map_err(|e| format!("write hostapd config {} failed: {e}", path.display()))?;
            path.to_path_buf()
        }
        None => {
            let path = std::env::temp_dir().join(format!("skymesh-hostapd-{}.conf", now_ms()));
            std::fs::write(&path, rendered.as_bytes())
                .map_err(|e| format!("write hostapd config {} failed: {e}", path.display()))?;
            path
        }
    };

    eprintln!(
        "[skymesh-wifi-pluto] ap config written: {} (ssid={} interface={})",
        config_path.display(),
        cfg.ap_ssid,
        cfg.ap_interface.as_deref().unwrap_or("?")
    );

    if cfg.ap_config_only || !cfg.ap_run_hostapd {
        return Ok(None);
    }
    if !cfg!(target_os = "linux") {
        return Err(format!(
            "--ap-run-hostapd is only supported on Linux; this host is {}. \
             Use macOS Internet Sharing or a router to create the visible SSID, \
             then run this endpoint on that network.",
            std::env::consts::OS
        ));
    }

    let child = Command::new(&cfg.hostapd_bin)
        .arg(&config_path)
        .stdin(Stdio::null())
        .spawn()
        .map_err(|e| {
            format!(
                "spawn {} {} failed: {e}",
                cfg.hostapd_bin,
                config_path.display()
            )
        })?;
    eprintln!(
        "[skymesh-wifi-pluto] hostapd started for SSID '{}' using {}",
        cfg.ap_ssid,
        config_path.display()
    );
    Ok(Some(child))
}

fn http_url(cfg: &Config) -> String {
    let port = cfg
        .http_bind
        .rsplit_once(':')
        .map(|(_, port)| port)
        .unwrap_or("8732");
    format!("http://{}:{}", cfg.public_host, port)
}

fn advertisement(cfg: &Config) -> Advertisement {
    Advertisement {
        schema_version: "gnosis.skymesh.wifi-pluto.advertisement.v1",
        service: "skymesh-wifi-pluto",
        node_id: cfg.node_id.clone(),
        service_id: cfg.service_id.clone(),
        http_url: http_url(cfg),
        pluto_uri: cfg.pluto_uri.clone(),
        tx_enabled: cfg.enable_tx,
        endpoints: vec![
            "GET /healthz",
            "GET /advertisement",
            "GET /pluto/preflight",
            "POST /pluto/transmit",
        ],
        unix_ms: now_ms(),
    }
}

fn preflight(cfg: &Config) -> PlutoPreflight {
    let framework = cfg.libiio_build.join("iio.framework/iio");
    let missing = [
        ("libiio framework", framework.as_path()),
        ("iio_attr", cfg.iio_attr.as_path()),
        ("iio_writedev", cfg.iio_writedev.as_path()),
    ]
    .iter()
    .filter_map(|(label, path)| {
        if path.exists() {
            None
        } else {
            Some(format!("{label} missing at {}", path.display()))
        }
    })
    .collect::<Vec<_>>();

    PlutoPreflight {
        ok: missing.is_empty(),
        tx_enabled: cfg.enable_tx,
        pluto_uri: cfg.pluto_uri.clone(),
        libiio_build: cfg.libiio_build.display().to_string(),
        framework: framework.display().to_string(),
        iio_attr: cfg.iio_attr.display().to_string(),
        iio_writedev: cfg.iio_writedev.display().to_string(),
        reason: if missing.is_empty() {
            None
        } else {
            Some(missing.join("; "))
        },
    }
}

fn pluto_setup_cmds(cfg: &Config, req: &TxRequest) -> Vec<Vec<String>> {
    let tx_lo_hz = req.tx_lo_hz.unwrap_or(cfg.default_tx_lo_hz);
    let sample_rate_hz = req.sample_rate_hz.unwrap_or(cfg.default_sample_rate_hz);
    let rf_bandwidth_hz = req.rf_bandwidth_hz.unwrap_or(cfg.default_rf_bandwidth_hz);
    let gain_db = req.hardwaregain_db.unwrap_or(cfg.default_gain_db);
    let attr = cfg.iio_attr.display().to_string();
    vec![
        vec![
            attr.clone(),
            "-u".into(),
            cfg.pluto_uri.clone(),
            "-c".into(),
            "ad9361-phy".into(),
            "altvoltage1".into(),
            "frequency".into(),
            tx_lo_hz.to_string(),
        ],
        vec![
            attr.clone(),
            "-u".into(),
            cfg.pluto_uri.clone(),
            "-c".into(),
            "ad9361-phy".into(),
            "voltage0".into(),
            "sampling_frequency".into(),
            sample_rate_hz.to_string(),
        ],
        vec![
            attr.clone(),
            "-u".into(),
            cfg.pluto_uri.clone(),
            "-c".into(),
            "ad9361-phy".into(),
            "voltage0".into(),
            "rf_bandwidth".into(),
            rf_bandwidth_hz.to_string(),
        ],
        vec![
            attr,
            "-u".into(),
            cfg.pluto_uri.clone(),
            "-c".into(),
            "ad9361-phy".into(),
            "voltage0".into(),
            "hardwaregain".into(),
            gain_db.to_string(),
        ],
    ]
}

fn pluto_writedev_cmd(cfg: &Config, req: &TxRequest) -> Vec<String> {
    let mut cmd = vec![
        cfg.iio_writedev.display().to_string(),
        "-u".into(),
        cfg.pluto_uri.clone(),
        "-b".into(),
        req.buffer_size
            .unwrap_or(cfg.default_buffer_size)
            .to_string(),
    ];
    if req.cyclic.unwrap_or(true) {
        cmd.push("-c".into());
    }
    cmd.extend(
        ["cf-ad9361-dds-core-lpc", "voltage0", "voltage1"]
            .iter()
            .map(|s| s.to_string()),
    );
    cmd
}

fn run_command(argv: &[String], input_file: Option<&Path>) -> Result<(), String> {
    let (program, args) = argv
        .split_first()
        .ok_or_else(|| "empty command".to_string())?;
    let mut command = Command::new(program);
    command
        .args(args)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    if let Some(path) = input_file {
        let file = std::fs::File::open(path)
            .map_err(|e| format!("open {} failed: {e}", path.display()))?;
        command.stdin(Stdio::from(file));
    }
    let output = command
        .output()
        .map_err(|e| format!("spawn {program} failed: {e}"))?;
    if output.status.success() {
        Ok(())
    } else {
        Err(format!(
            "{} exited {}: {}",
            program,
            output.status,
            String::from_utf8_lossy(&output.stderr).trim()
        ))
    }
}

fn execute_transmit(cfg: &Config, req: &TxRequest) -> Result<serde_json::Value, String> {
    let iq_path = PathBuf::from(&req.iq_path);
    if !iq_path.exists() {
        return Err(format!("iq_path does not exist: {}", iq_path.display()));
    }
    let setup = pluto_setup_cmds(cfg, req);
    let writedev = pluto_writedev_cmd(cfg, req);
    if req.preflight_only.unwrap_or(false) || !cfg.enable_tx {
        return Ok(json!({
            "executed": false,
            "txEnabled": cfg.enable_tx,
            "reason": if cfg.enable_tx { "preflight_only" } else { "start with --enable-tx to execute Pluto transmit" },
            "setup": setup,
            "writedev": writedev,
            "stdin": iq_path,
        }));
    }

    let guard = preflight(cfg);
    if !guard.ok {
        return Err(guard
            .reason
            .unwrap_or_else(|| "Pluto preflight failed".to_string()));
    }
    for cmd in &setup {
        run_command(cmd, None)?;
    }
    run_command(&writedev, Some(&iq_path))?;
    Ok(json!({ "executed": true, "setup": setup, "writedev": writedev, "stdin": iq_path }))
}

fn json_response(status: u16, value: serde_json::Value) -> Response<std::io::Cursor<Vec<u8>>> {
    let body = serde_json::to_vec_pretty(&value).unwrap_or_else(|_| b"{\"ok\":false}".to_vec());
    let header = Header::from_bytes(
        &b"Content-Type"[..],
        &b"application/json; charset=utf-8"[..],
    )
    .expect("static header");
    Response::from_data(body)
        .with_status_code(StatusCode(status))
        .with_header(header)
}

fn read_json_body<T: for<'de> Deserialize<'de>>(req: &mut Request) -> Result<T, String> {
    let mut body = String::new();
    req.as_reader()
        .take(1024 * 1024)
        .read_to_string(&mut body)
        .map_err(|e| format!("read body failed: {e}"))?;
    serde_json::from_str(&body).map_err(|e| format!("invalid json: {e}"))
}

fn handle_request(mut req: Request, cfg: &Config) {
    let method = req.method().clone();
    let path = req.url().split('?').next().unwrap_or(req.url()).to_string();
    let remote = req
        .remote_addr()
        .map(|addr| addr.to_string())
        .unwrap_or_else(|| "unknown".to_string());
    eprintln!("[skymesh-wifi-pluto] {remote} {method} {path}");
    let response = match (method, path.as_str()) {
        (Method::Get, "/healthz") => {
            json_response(200, json!({ "ok": true, "service": "skymesh-wifi-pluto" }))
        }
        (Method::Get, "/advertisement") => json_response(
            200,
            serde_json::to_value(advertisement(cfg)).expect("advertisement json"),
        ),
        (Method::Get, "/pluto/preflight") => json_response(
            200,
            serde_json::to_value(preflight(cfg)).expect("preflight json"),
        ),
        (Method::Post, "/pluto/transmit") => {
            match read_json_body::<TxRequest>(&mut req).and_then(|tx| execute_transmit(cfg, &tx)) {
                Ok(value) => json_response(200, value),
                Err(error) => json_response(400, json!({ "ok": false, "error": error })),
            }
        }
        _ => json_response(404, json!({ "ok": false, "error": "not found" })),
    };
    if let Err(e) = req.respond(response) {
        eprintln!("[skymesh-wifi-pluto] respond failed: {e}");
    }
}

fn spawn_advertiser(cfg: Arc<Config>) {
    thread::spawn(move || {
        let target = format!("{}:{}", cfg.advertise_group, cfg.advertise_port);
        let socket = match UdpSocket::bind("0.0.0.0:0") {
            Ok(socket) => socket,
            Err(e) => {
                eprintln!("[skymesh-wifi-pluto] advertisement bind failed: {e}");
                return;
            }
        };
        let _ = socket.set_multicast_ttl_v4(1);
        loop {
            match serde_json::to_vec(&advertisement(&cfg)) {
                Ok(payload) => {
                    if let Err(e) = socket.send_to(&payload, &target) {
                        eprintln!("[skymesh-wifi-pluto] advertise to {target} failed: {e}");
                    }
                }
                Err(e) => eprintln!("[skymesh-wifi-pluto] advertisement encode failed: {e}"),
            }
            thread::sleep(cfg.advertise_interval);
        }
    });
}

fn main() {
    let cfg = Arc::new(parse_config());
    let _ap_child = match prepare_ap_mode(&cfg) {
        Ok(child) => child,
        Err(e) => {
            eprintln!("[skymesh-wifi-pluto] ap mode failed: {e}");
            std::process::exit(5);
        }
    };
    if cfg.ap_config_only {
        return;
    }
    spawn_advertiser(cfg.clone());

    let server = Server::http(&cfg.http_bind).unwrap_or_else(|e| {
        eprintln!("[skymesh-wifi-pluto] bind {} failed: {e}", cfg.http_bind);
        std::process::exit(4);
    });
    eprintln!(
        "[skymesh-wifi-pluto] http={} advertise={}:{} tx_enabled={} pluto={}",
        http_url(&cfg),
        cfg.advertise_group,
        cfg.advertise_port,
        cfg.enable_tx,
        cfg.pluto_uri
    );
    for req in server.incoming_requests() {
        handle_request(req, &cfg);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn test_config() -> Config {
        Config {
            http_bind: "0.0.0.0:9999".to_string(),
            public_host: "10.0.0.7".to_string(),
            advertise_group: DEFAULT_ADVERTISE_GROUP.to_string(),
            advertise_port: DEFAULT_ADVERTISE_PORT,
            advertise_interval: Duration::from_millis(DEFAULT_INTERVAL_MS),
            node_id: "node-a".to_string(),
            service_id: "svc".to_string(),
            enable_tx: false,
            pluto_uri: "usb:0.5.5".to_string(),
            libiio_build: PathBuf::from(DEFAULT_LIBIIO_BUILD),
            iio_attr: PathBuf::from(DEFAULT_IIO_ATTR),
            iio_writedev: PathBuf::from(DEFAULT_IIO_WRITEDEV),
            default_tx_lo_hz: DEFAULT_TX_LO_HZ,
            default_sample_rate_hz: DEFAULT_SAMPLE_RATE_HZ,
            default_gain_db: DEFAULT_GAIN_DB,
            default_rf_bandwidth_hz: DEFAULT_RF_BANDWIDTH_HZ,
            default_buffer_size: DEFAULT_BUFFER_SIZE,
            ap_mode: false,
            ap_interface: None,
            ap_ssid: DEFAULT_AP_SSID.to_string(),
            ap_channel: DEFAULT_AP_CHANNEL,
            ap_passphrase: None,
            ap_config_out: None,
            ap_config_only: false,
            ap_run_hostapd: false,
            hostapd_bin: DEFAULT_HOSTAPD_BIN.to_string(),
        }
    }

    #[test]
    fn advertisement_uses_public_host_and_http_port() {
        let cfg = test_config();
        let adv = advertisement(&cfg);
        assert_eq!(adv.http_url, "http://10.0.0.7:9999");
        assert_eq!(
            adv.schema_version,
            "gnosis.skymesh.wifi-pluto.advertisement.v1"
        );
    }

    #[test]
    fn tx_request_builds_guarded_libiio_commands() {
        let cfg = test_config();
        let req = TxRequest {
            iq_path: "/tmp/skymesh.i16".to_string(),
            tx_lo_hz: Some(915_000_000),
            sample_rate_hz: None,
            hardwaregain_db: Some(-50),
            rf_bandwidth_hz: None,
            buffer_size: Some(8192),
            cyclic: Some(false),
            preflight_only: Some(true),
        };
        let setup = pluto_setup_cmds(&cfg, &req);
        assert!(setup[0].contains(&"915000000".to_string()));
        assert!(setup[3].contains(&"-50".to_string()));
        let writedev = pluto_writedev_cmd(&cfg, &req);
        assert!(writedev.contains(&"8192".to_string()));
        assert!(!writedev.contains(&"-c".to_string()));
    }

    #[test]
    fn ap_mode_renders_hostapd_config_for_visible_skymesh_ssid() {
        let mut cfg = test_config();
        cfg.ap_mode = true;
        cfg.ap_interface = Some("wlan0".to_string());
        cfg.ap_ssid = "skymesh".to_string();
        cfg.ap_channel = 11;
        cfg.ap_config_out = Some(PathBuf::from("/tmp/skymesh-hostapd-test.conf"));
        let rendered = hostapd_config(&cfg).expect("hostapd config");
        assert!(rendered.contains("interface=wlan0\n"));
        assert!(rendered.contains("ssid=skymesh\n"));
        assert!(rendered.contains("channel=11\n"));
        assert!(rendered.contains("ignore_broadcast_ssid=0\n"));
    }
}
